sql:
SELECT COUNT(*) AS num_episodes
FROM episodes
WHERE season_id = 2;

SELECT season_id, COUNT(episode_id) AS number_of_episodes
FROM episodes
GROUP BY season_id;

SELECT COUNT(*) 
FROM ratings 
WHERE ai_score > 8.0;

SELECT title, runtime
FROM episodes
ORDER BY runtime DESC;

SELECT DISTINCT T1.episode_id
FROM episodes AS T1
INNER JOIN ratings AS T2 ON T1.episode_id = T2.episode_id;

external_knowledge:
- "first glimpse of morning sunlight" is used metaphorically to refer to the first record in the ordered data;
- "bloomed with more than a million viewers" refers to the condition of having more than a million UK viewers;
- "season that sprouted from the fertile ground of 2021" is a metaphorical expression for the broadcast start date being between January 1, 2021, and December 31, 2021.

sql:
SELECT episode_id, AVG(rating) AS average_rating
FROM episodes
GROUP BY episode_id;

SELECT viewers
FROM episodes
ORDER BY viewers DESC;
